{"result":"{
  "version": "2.1.0",
  "pipelines": {
    "data_ingestion": {
      "id": "pipeline-001",
      "schedule": "0 */6 * * *",
      "source": {
        "type": "kafka",
        "topics": ["raw-events", "user-actions"],
        "consumer_group": "ingestion_consumer_group",
        "bootstrap_servers": ["kafka-1:9092", "kafka-2:9092", "kafka-3:9092"]
      },
      "sink": {
        "type": "postgres",
        "connection": "postgresql://datauser:****@db.internal:5432/warehouse",
        "table": "raw_events",
        "batch_size": 1000
      },
      "retry_policy": {
        "max_retries": 3,
        "backoff_ms": 1000,
        "exponential": true
      }
    },
    "data_transformation": {
      "id": "pipeline-002",
      "schedule": "30 */6 * * *",
      "depends_on": ["pipeline-001"],
      "spark_config": {
        "executor_memory": "4g",
        "executor_cores": 2,
        "num_executors": 10
      }
    },
    "data_export": {
      "id": "pipeline-003",
      "schedule": "0 2 * * *",
      "depends_on": ["pipeline-002"],
      "destination": {
        "type": "s3",
        "bucket": "data-warehouse-exports",
        "prefix": "daily/"
      }
    }
  },
  "alerting": {
    "slack_webhook": "https://hooks.slack.com/services/xxx/yyy/zzz",
    "pagerduty_key": "pd-service-key-xxx",
    "alert_on": ["pipeline_failure", "data_quality_issue", "latency_threshold"]
  },
  "monitoring": {
    "metrics_endpoint": "http://prometheus:9090",
    "log_level": "INFO",
    "trace_sampling_rate": 0.1
  }
}
"}

