{"result":"{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "title": "Customer",
  "description": "Customer data schema for the data warehouse",
  "type": "object",
  "required": ["customer_id", "email", "created_at"],
  "properties": {
    "customer_id": {
      "type": "integer",
      "description": "Unique customer identifier",
      "minimum": 1
    },
    "email": {
      "type": "string",
      "format": "email",
      "description": "Customer email address"
    },
    "first_name": {
      "type": "string",
      "maxLength": 100
    },
    "last_name": {
      "type": "string",
      "maxLength": 100
    },
    "ip_address": {
      "type": "string",
      "pattern": "^(?:(?:25[0-5]|2[0-4][0-9]|[01]?[0-9][0-9]?)\\.){3}(?:25[0-5]|2[0-4][0-9]|[01]?[0-9][0-9]?)$",
      "description": "Customer IP address for geo-location"
    },
    "region": {
      "type": "string",
      "enum": ["NA", "EU", "APAC", "LATAM", "MEA"],
      "description": "Geographic region"
    },
    "tier": {
      "type": "string",
      "enum": ["free", "basic", "premium", "enterprise"],
      "default": "free"
    },
    "created_at": {
      "type": "string",
      "format": "date-time"
    },
    "updated_at": {
      "type": "string",
      "format": "date-time"
    },
    "metadata": {
      "type": "object",
      "additionalProperties": true
    },
    "preferences": {
      "type": "object",
      "properties": {
        "newsletter": {"type": "boolean", "default": false},
        "marketing_emails": {"type": "boolean", "default": false},
        "language": {"type": "string", "default": "en"},
        "timezone": {"type": "string"}
      }
    },
    "enrichment": {
      "type": "object",
      "properties": {
        "company": {"type": "string"},
        "industry": {"type": "string"},
        "geo_data": {
          "type": "object",
          "properties": {
            "country": {"type": "string"},
            "city": {"type": "string"},
            "latitude": {"type": "number"},
            "longitude": {"type": "number"}
          }
        }
      }
    }
  },
  "additionalProperties": false
}
"}

