                errors.append(f"Missing required field: {field}")

        if 'email' in record and not cls.validate_email(record['email']):
            errors.append(f"Invalid email format: {record['email']}")

        if 'ip_address' in record and not cls.validate_ip_address(record['ip_address']):
            errors.append(f"Invalid IP address: {record['ip_address']}")

        return len(errors) == 0, errors


class Transformer:
    """Handles data transformations."""

    @staticmethod
    def normalize_timestamp(ts: str) -> str:
        """Normalize timestamp to ISO format."""
        formats = [
            '%Y-%m-%d %H:%M:%S',
            '%Y-%m-%dT%H:%M:%S',
            '%Y-%m-%dT%H:%M:%SZ',
            '%Y-%m-%d',
        ]
        for fmt in formats:
            try:
                dt = datetime.strptime(ts, fmt)
                return dt.isoformat() + 'Z'
            except ValueError:
                continue
        raise ValueError(f"Unable to parse timestamp: {ts}")

    @staticmethod
    def hash_pii(value: str, salt: str = "default_salt") -> str:
        """Hash PII data for anonymization."""
        return hashlib.sha256(f"{value}{salt}".encode()).hexdigest()[:16]

    @staticmethod
    def calculate_customer_tier(total_orders: int, total_spent: float) -> str:
        """Determine customer tier based on activity."""
        if total_spent >= 10000 or total_orders >= 50:
            return "enterprise"
        elif total_spent >= 1000 or total_orders >= 20:
            return "premium"
        elif total_spent >= 100 or total_orders >= 5:
            return "basic"
        return "free"

    @staticmethod
    def enrich_geo_data(ip_address: str) -> Dict[str, Any]:
        """Placeholder for geo enrichment - would call external API."""
        # Simulated geo data based on IP ranges
        first_octet = int(ip_address.split('.')[0])
        regions = {
            range(1, 50): {"country": "US", "region": "NA", "city": "New York"},
            range(50, 100): {"country": "GB", "region": "EU", "city": "London"},
            range(100, 150): {"country": "DE", "region": "EU", "city": "Berlin"},
            range(150, 200): {"country": "JP", "region": "APAC", "city": "Tokyo"},
            range(200, 256): {"country": "AU", "region": "APAC", "city": "Sydney"},
        }
        for ip_range, data in regions.items():
            if first_octet in ip_range:
                return data
        return {"country": "Unknown", "region": "Unknown", "city": "Unknown"}


class ETLProcessor:
    """Main ETL processor class."""

    def __init__(self, config: Dict):
        self.config = config
        self.validator = DataValidator()
        self.transformer = Transformer()
        self.processed_count = 0
        self.error_count = 0
        self.errors: List[Dict] = []

    def process_batch(self, records: List[Dict]) -> List[Dict]:
        """Process a batch of records."""
        results = []

        for record in records:
            try:
                # Validate
                is_valid, errors = self.validator.validate_customer(record)
                if not is_valid:
                    self.error_count += 1
                    self.errors.append({
                        "record_id": record.get("customer_id"),
                        "errors": errors
                    })
                    continue

                # Transform
                transformed = self._transform_record(record)
                results.append(transformed)
                self.processed_count += 1

            except Exception as e:
                logger.error(f"Error processing record: {e}")
                self.error_count += 1

        return results

    def _transform_record(self, record: Dict) -> Dict:
        """Apply transformations to a single record."""
        result = record.copy()

        # Normalize timestamps
        if 'created_at' in result:
            result['created_at'] = self.transformer.normalize_timestamp(result['created_at'])

        # Enrich with geo data
        if 'ip_address' in result:
            result['geo_data'] = self.transformer.enrich_geo_data(result['ip_address'])

        # Hash sensitive fields if configured
        if self.config.get('anonymize_pii', False):
            if 'email' in result:
                result['email_hash'] = self.transformer.hash_pii(result['email'])

        result['processed_at'] = datetime.utcnow().isoformat() + 'Z'
        return result

    def get_stats(self) -> Dict:
        """Return processing statistics."""
        return {
            "processed": self.processed_count,
            "errors": self.error_count,
            "success_rate": self.processed_count / (self.processed_count + self.error_count) if (self.processed_count + self.error_count) > 0 else 0
        }


def main():
    """Example usage."""
    config = {
        "anonymize_pii": True,
        "batch_size": 1000
    }

    processor = ETLProcessor(config)

    # Sample data
    sample_records = [
        {
            "customer_id": 1,
            "email": "user@example.com",
            "ip_address": "45.67.89.123",
            "created_at": "2024-01-15 10:30:00"
        },
        {
            "customer_id": 2,
            "email": "another@test.org",
            "ip_address": "120.45.67.89",
            "created_at": "2024-01-16T14:20:00Z"
        }
    ]

    results = processor.process_batch(sample_records)
    print(json.dumps(results, indent=2))
    print(f"Stats: {processor.get_stats()}")


if __name__ == "__main__":
    main()
"}

