{"result":"#!/usr/bin/env python3
"""
Data Validation Module
Provides comprehensive data quality checks for the pipeline.
"""

import re
from datetime import datetime
from typing import Dict, List, Tuple, Any, Optional
from dataclasses import dataclass
from enum import Enum


class Severity(Enum):
    INFO = "info"
    WARNING = "warning"
    ERROR = "error"
    CRITICAL = "critical"


@dataclass
class ValidationResult:
    """Result of a validation check."""
    check_name: str
    passed: bool
    severity: Severity
    message: str
    details: Optional[Dict] = None


class SchemaValidator:
    """Validates data against JSON schema rules."""

    TYPE_MAP = {
        'string': str,
        'integer': int,
        'number': (int, float),
        'boolean': bool,
        'array': list,
        'object': dict,
    }

    def validate(self, data: Dict, schema: Dict) -> List[ValidationResult]:
        """Validate data against schema."""
        results = []

        # Check required fields
        required = schema.get('required', [])
        for field in required:
            if field not in data:
                results.append(ValidationResult(
                    check_name=f"required_field_{field}",
                    passed=False,
                    severity=Severity.ERROR,
                    message=f"Missing required field: {field}"
                ))

        # Check field types and constraints
        properties = schema.get('properties', {})
        for field, constraints in properties.items():
            if field in data:
                field_results = self._validate_field(field, data[field], constraints)
                results.extend(field_results)

        return results

    def _validate_field(self, name: str, value: Any, constraints: Dict) -> List[ValidationResult]:
        """Validate a single field."""
        results = []

        # Type check
        expected_type = constraints.get('type')
        if expected_type and expected_type in self.TYPE_MAP:
            if not isinstance(value, self.TYPE_MAP[expected_type]):
                results.append(ValidationResult(
                    check_name=f"type_{name}",
                    passed=False,
                    severity=Severity.ERROR,
                    message=f"Field {name} has wrong type. Expected {expected_type}, got {type(value).__name__}"
                ))
                return results  # Skip further checks if type is wrong

        # String constraints
        if expected_type == 'string':
            if 'maxLength' in constraints and len(value) > constraints['maxLength']:
                results.append(ValidationResult(
                    check_name=f"maxLength_{name}",
                    passed=False,
                    severity=Severity.WARNING,
                    message=f"Field {name} exceeds max length of {constraints['maxLength']}"
                ))

            if 'pattern' in constraints and not re.match(constraints['pattern'], value):
                results.append(ValidationResult(
                    check_name=f"pattern_{name}",
                    passed=False,
                    severity=Severity.ERROR,
                    message=f"Field {name} does not match pattern {constraints['pattern']}"
                ))

            if 'enum' in constraints and value not in constraints['enum']:
                results.append(ValidationResult(
                    check_name=f"enum_{name}",
                    passed=False,
                    severity=Severity.ERROR,
                    message=f"Field {name} has invalid value. Must be one of {constraints['enum']}"
                ))

        # Numeric constraints
        if expected_type in ('integer', 'number'):
            if 'minimum' in constraints and value < constraints['minimum']:
                results.append(ValidationResult(
                    check_name=f"minimum_{name}",
                    passed=False,
                    severity=Severity.ERROR,
                    message=f"Field {name} is below minimum of {constraints['minimum']}"
                ))

            if 'maximum' in constraints and value > constraints['maximum']:
                results.append(ValidationResult(
                    check_name=f"maximum_{name}",
                    passed=False,
                    severity=Severity.ERROR,
                    message=f"Field {name} exceeds maximum of {constraints['maximum']}"
                ))

        return results


class DataQualityChecker:
    """Performs data quality checks on datasets."""

    def __init__(self, config: Optional[Dict] = None):
        self.config = config or {}
        self.thresholds = self.config.get('thresholds', {
            'null_rate': 0.05,
            'duplicate_rate': 0.01,
            'outlier_zscore': 3.0,
        })

    def check_completeness(self, data: List[Dict], required_fields: List[str]) -> ValidationResult:
        """Check data completeness."""
        if not data:
            return ValidationResult(
                check_name="completeness",
                passed=False,
                severity=Severity.CRITICAL,
                message="Dataset is empty"
            )

        missing_counts = {field: 0 for field in required_fields}
        for record in data:
            for field in required_fields:
                if field not in record or record[field] is None:
                    missing_counts[field] += 1

        total_records = len(data)
        issues = {k: v/total_records for k, v in missing_counts.items() if v > 0}

        if any(rate > self.thresholds['null_rate'] for rate in issues.values()):
            return ValidationResult(
                check_name="completeness",
                passed=False,
                severity=Severity.ERROR,
                message="Data completeness below threshold",
                details={"null_rates": issues}
            )

        return ValidationResult(
            check_name="completeness",
            passed=True,
            severity=Severity.INFO,
            message="Data completeness check passed"
        )

    def check_uniqueness(self, data: List[Dict], key_fields: List[str]) -> ValidationResult:
        """Check for duplicate records."""
        if not data:
            return ValidationResult(
                check_name="uniqueness",
                passed=True,
                severity=Severity.INFO,
                message="No data to check"
            )

        seen = set()
        duplicates = 0

        for record in data:
            key = tuple(record.get(f) for f in key_fields)
            if key in seen:
                duplicates += 1
            else:
                seen.add(key)

        duplicate_rate = duplicates / len(data)

        if duplicate_rate > self.thresholds['duplicate_rate']:
            return ValidationResult(
                check_name="uniqueness",
                passed=False,
                severity=Severity.WARNING,
                message=f"Duplicate rate ({duplicate_rate:.2%}) exceeds threshold",
                details={"duplicate_count": duplicates, "duplicate_rate": duplicate_rate}
            )

        return ValidationResult(
            check_name="uniqueness",
            passed=True,
            severity=Severity.INFO,
            message="Uniqueness check passed"
        )

    def check_freshness(self, data: List[Dict], timestamp_field: str, max_age_hours: int = 24) -> ValidationResult:
        """Check data freshness."""
        if not data:
            return ValidationResult(
                check_name="freshness",
                passed=False,
                severity=Severity.WARNING,
                message="No data to check freshness"
            )

        now = datetime.utcnow()
        max_age = None

        for record in data:
            if timestamp_field in record:
                try:
                    ts = datetime.fromisoformat(record[timestamp_field].replace('Z', '+00:00'))
                    age = (now - ts.replace(tzinfo=None)).total_seconds() / 3600
                    if max_age is None or age > max_age:
                        max_age = age
                except (ValueError, TypeError):
                    continue

        if max_age is None:
            return ValidationResult(
                check_name="freshness",
                passed=False,
                severity=Severity.WARNING,
                message=f"Could not determine data freshness - no valid {timestamp_field} found"
            )

        if max_age > max_age_hours:
            return ValidationResult(
                check_name="freshness",
                passed=False,
                severity=Severity.WARNING,
                message=f"Data is {max_age:.1f} hours old (threshold: {max_age_hours}h)",
                details={"max_age_hours": max_age}
            )

        return ValidationResult(
            check_name="freshness",
            passed=True,
            severity=Severity.INFO,
            message=f"Data freshness OK ({max_age:.1f}h old)"
        )


def run_all_checks(data: List[Dict], schema: Dict) -> Tuple[bool, List[ValidationResult]]:
    """Run all validation checks on a dataset."""
    results = []

    # Schema validation on sample
    schema_validator = SchemaValidator()
    for record in data[:10]:  # Validate first 10 records
        results.extend(schema_validator.validate(record, schema))

    # Quality checks
    quality_checker = DataQualityChecker()
    required_fields = schema.get('required', [])

    results.append(quality_checker.check_completeness(data, required_fields))
    results.append(quality_checker.check_uniqueness(data, ['customer_id']))
    results.append(quality_checker.check_freshness(data, 'created_at', 48))

    all_passed = all(r.passed for r in results)
    return all_passed, results


if __name__ == "__main__":
    # Example usage
    sample_data = [
        {"customer_id": 1, "email": "test@example.com", "created_at": "2024-01-15T10:00:00Z"},
        {"customer_id": 2, "email": "user@test.org", "created_at": "2024-01-15T11:00:00Z"},
    ]

    sample_schema = {
        "required": ["customer_id", "email"],
        "properties": {
            "customer_id": {"type": "integer", "minimum": 1},
            "email": {"type": "string", "maxLength": 255}
        }
    }

    passed, results = run_all_checks(sample_data, sample_schema)
    print(f"All checks passed: {passed}")
    for r in results:
        print(f"  [{r.severity.value}] {r.check_name}: {r.message}")
"}

